func formatDuration(d time.Duration) string {
	if d == 0 {
		return "-"
	}
	if d%time.Hour == 0 {
		return strconv.Itoa(int(d/time.Hour)) + "h"
	}
	if d%time.Minute == 0 {
		return strconv.Itoa(int(d/time.Minute)) + "min"
	}
	return d.String()
}

